create table if not exists public.verification_badges(id uuid primary key default gen_random_uuid(),subject_type text not null check(subject_type in('user','community','role')),subject_id uuid not null,badge_kind text not null check(badge_kind in('profile_reviewed','community_official','role_managed')),label text not null check(char_length(label) between 3 and 40),scope_note text not null check(char_length(scope_note) between 20 and 240),granted_by uuid not null references public.profiles(id) on delete restrict,granted_at timestamptz not null default now(),revoked_at timestamptz,revoked_by uuid references public.profiles(id) on delete restrict);
create unique index if not exists idx_verification_badges_active_subject_kind on public.verification_badges(subject_type,subject_id,badge_kind) where revoked_at is null;
create table if not exists public.verification_badge_audit(id uuid primary key default gen_random_uuid(),badge_id uuid not null references public.verification_badges(id) on delete restrict,actor_id uuid not null references public.profiles(id) on delete restrict,action text not null check(action in('grant','revoke')),subject_type text not null,subject_id uuid not null,badge_kind text not null,reason text not null check(char_length(reason) between 10 and 500),created_at timestamptz not null default now());
alter table public.verification_badges enable row level security;
alter table public.verification_badge_audit enable row level security;
revoke all on public.verification_badges,public.verification_badge_audit from public,anon,authenticated;
create policy "verification_audit_app_admin_select" on public.verification_badge_audit for select to authenticated using(public.is_app_admin());
create or replace function public.validate_verification_subject(target_subject_type text,target_subject_id uuid) returns boolean language sql stable security definer set search_path=public as $$select case target_subject_type when 'user' then exists(select 1 from public.profiles where id=target_subject_id) when 'community' then exists(select 1 from public.communities where id=target_subject_id) when 'role' then exists(select 1 from public.roles where id=target_subject_id) else false end;$$;
create or replace function public.list_active_verification_badges(target_subject_type text,target_subject_id uuid) returns table(id uuid,subject_type text,subject_id uuid,badge_kind text,label text,scope_note text,granted_at timestamptz,revoked_at timestamptz) language sql stable security definer set search_path=public as $$select badge.id,badge.subject_type,badge.subject_id,badge.badge_kind,badge.label,badge.scope_note,badge.granted_at,badge.revoked_at from public.verification_badges badge where badge.subject_type=target_subject_type and badge.subject_id=target_subject_id and badge.revoked_at is null order by badge.granted_at;$$;
create or replace function public.list_recent_verification_badges(result_limit integer default 100) returns table(id uuid,subject_type text,subject_id uuid,badge_kind text,label text,scope_note text,granted_at timestamptz,revoked_at timestamptz) language plpgsql stable security definer set search_path=public as $$begin if not public.is_app_admin() then raise exception 'APP_ADMIN_REQUIRED' using errcode='42501';end if;return query select badge.id,badge.subject_type,badge.subject_id,badge.badge_kind,badge.label,badge.scope_note,badge.granted_at,badge.revoked_at from public.verification_badges badge order by badge.granted_at desc limit least(greatest(result_limit,1),100);end$$;
create or replace function public.grant_verification_badge(target_subject_type text,target_subject_id uuid,target_badge_kind text,target_label text,target_scope_note text,grant_reason text) returns setof public.verification_badges language plpgsql security definer set search_path=public as $$declare badge public.verification_badges%rowtype;begin if not public.is_app_admin() then raise exception 'APP_ADMIN_REQUIRED' using errcode='42501';end if;if target_subject_type not in('user','community','role') or target_badge_kind not in('profile_reviewed','community_official','role_managed') or not public.validate_verification_subject(target_subject_type,target_subject_id) then raise exception 'VERIFICATION_SUBJECT_INVALID' using errcode='22023';end if;if char_length(btrim(grant_reason))<10 then raise exception 'VERIFICATION_REASON_REQUIRED' using errcode='22023';end if;insert into public.verification_badges(subject_type,subject_id,badge_kind,label,scope_note,granted_by) values(target_subject_type,target_subject_id,target_badge_kind,btrim(target_label),btrim(target_scope_note),auth.uid()) returning * into badge;insert into public.verification_badge_audit(badge_id,actor_id,action,subject_type,subject_id,badge_kind,reason) values(badge.id,auth.uid(),'grant',badge.subject_type,badge.subject_id,badge.badge_kind,public.redact_audit_reason(grant_reason));return next badge;end$$;
create or replace function public.revoke_verification_badge(target_badge_id uuid,revoke_reason text) returns boolean language plpgsql security definer set search_path=public as $$declare badge public.verification_badges%rowtype;begin if not public.is_app_admin() then raise exception 'APP_ADMIN_REQUIRED' using errcode='42501';end if;if char_length(btrim(revoke_reason))<10 then raise exception 'VERIFICATION_REASON_REQUIRED' using errcode='22023';end if;update public.verification_badges set revoked_at=now(),revoked_by=auth.uid() where id=target_badge_id and revoked_at is null returning * into badge;if badge.id is null then return false;end if;insert into public.verification_badge_audit(badge_id,actor_id,action,subject_type,subject_id,badge_kind,reason) values(badge.id,auth.uid(),'revoke',badge.subject_type,badge.subject_id,badge.badge_kind,public.redact_audit_reason(revoke_reason));return true;end$$;
revoke all on function public.validate_verification_subject(text,uuid),public.list_active_verification_badges(text,uuid),public.list_recent_verification_badges(integer),public.grant_verification_badge(text,uuid,text,text,text,text),public.revoke_verification_badge(uuid,text) from public,anon;
grant execute on function public.list_active_verification_badges(text,uuid) to authenticated;
grant execute on function public.list_recent_verification_badges(integer),public.grant_verification_badge(text,uuid,text,text,text,text),public.revoke_verification_badge(uuid,text) to authenticated;
comment on table public.verification_badges is 'Review-scope markers only. Never represents a legal identity, safety, quality, endorsement, payment, or reputation guarantee.';
